// Worked focus: http-ts-destination-validation — Canonicalize and validate schemes, hosts, IP literals, ports, IDNs, and resolved destinations before granting network authority. Demonstrate the result through TypeScript 7 strict types plus WHATWG Fetch Request, Response, Headers, URL, streams, and AbortSignal contracts.
function worked_http_ts_uris_origins_dns_4(target: string, allowedHosts: readonly string[]): { accepted: boolean; host: string } {
  try {
    const parsed = new URL(target);
    const accepted = parsed.protocol === "https:" && allowedHosts.includes(parsed.hostname);
    return { accepted, host: parsed.hostname };
  } catch {
    return { accepted: false, host: "invalid" };
  }
}

